import sys
input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    # dp: dict lo -> min_span
    dp = {0: 0}

    for ai in a:
        ndp = {}
        for lo, span in dp.items():
            # Right
            nlo = lo + ai
            nspan = max(span, nlo)
            if nlo not in ndp or ndp[nlo] > nspan:
                ndp[nlo] = nspan
            # Left
            if lo >= ai:
                nlo = lo - ai
                nspan = span
            else:
                nlo = 0
                nspan = span + (ai - lo)
            if nlo not in ndp or ndp[nlo] > nspan:
                ndp[nlo] = nspan
        dp = ndp

    print(min(dp.values()))

t = int(input())
for _ in range(t):
    solve()

